'use client';

import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { User } from '@/lib/types';
import api from '@/lib/api';
import { useToast } from '@/hooks/use-toast';

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (email: string, password: string) => Promise<boolean>;
  register: (username: string, firstName: string, lastName: string, email: string, password: string) => Promise<boolean>;
  logout: () => Promise<void>;
  refreshAuth: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const router = useRouter();
  const pathname = usePathname(); // Get current pathname
  const { toast } = useToast();

  const loadUser = useCallback(async () => {
    console.log('Attempting to load user...');
    try {
      setIsLoading(true);
      const response = await api.auth.getProfile();
      if (response.data.success) {
        setUser(response.data.user);
      } else {
        setUser(null);
      }
    } catch (error: any) {
      console.error('Failed to load user:', error.response?.data || error.message || error);
      setUser(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    // Do not attempt to load user on login or signup pages
    if (pathname === '/login' || pathname === '/signup') {
      setIsLoading(false);
      return;
    }
    loadUser();
  }, [loadUser, pathname]);

  useEffect(() => {
    const handleSessionExpired = () => {
      toast({
        title: 'Session expired',
        description: 'Please log in again.',
        variant: 'destructive',
      });
    };

    const handleTokenReplay = (event: CustomEvent) => {
      toast({
        title: 'Security Alert',
        description: event.detail?.message || 'Security violation detected. Please log in again.',
        variant: 'destructive',
      });
      setUser(null);
    };

    window.addEventListener('auth:session-expired', handleSessionExpired);
    window.addEventListener('auth:token-replay-detected', handleTokenReplay as EventListener);

    return () => {
      window.removeEventListener('auth:session-expired', handleSessionExpired);
      window.removeEventListener('auth:token-replay-detected', handleTokenReplay as EventListener);
    };
  }, [toast]);

  const login = useCallback(async (email: string, password: string): Promise<boolean> => {
    console.log('Login function called with email:', email);
    setIsLoading(true);
    try {
      const response = await api.auth.login({ email, password });
      if (response.data.success) {
        // Set user directly from login response
        setUser(response.data.user);
        toast({
          title: 'Login successful',
          description: 'Welcome back!',
        });
        return true;
      } else {
        toast({
          title: 'Login failed',
          description: response.data.message || 'Invalid credentials',
          variant: 'destructive', 
        });
        return false;
      }
    } catch (error: any) {
      console.error('Login error:', error.response?.data || error.message || error);
      toast({
        title: 'Login failed',
        description: error.response?.data?.message || 'Network error occurred',
        variant: 'destructive',
      });
      return false;
    } finally {
      setIsLoading(false);
    }
  }, [toast]);

  const register = useCallback(async (username: string, firstName: string, lastName: string, email: string, password: string): Promise<boolean> => {
    setIsLoading(true);
    try {
      const response = await api.auth.register({ username, firstName, lastName, email, password });
      if (response.data.success) {
        setUser(response.data.user);
        toast({
          title: 'Registration successful',
          description: 'Welcome!',
        });
        return true;
      } else {
        toast({
          title: 'Registration failed',
          description: response.data.message || 'Please check your details',
          variant: 'destructive',
        });
        return false;
      }
    } catch (error: any) {
      console.error('Registration error:', error.response?.data || error.message || error);
      toast({
        title: 'Registration failed',
        description: error.response?.data?.message || 'A network error occurred',
        variant: 'destructive',
      });
      return false;
    } finally {
      setIsLoading(false);
    }
  }, [toast]);

  const logout = useCallback(async () => {
    try {
      // Enhanced security logout - requires authentication
      await api.auth.logout();
      setUser(null);
      router.push('/login');
      toast({
        title: 'Logged out',
        description: 'You have been logged out successfully.',
      });
    } catch (error: any) {
      console.error('Logout error:', error);

      // Handle specific logout errors
      if (error.response?.status === 401) {
        // User was already logged out or token invalid
        setUser(null);
        router.push('/login');
        toast({
          title: 'Session expired',
          description: 'You have been logged out due to session expiry.',
          variant: 'destructive',
        });
      } else {
        toast({
          title: 'Logout failed',
          description: 'Failed to log out. Please try again.',
          variant: 'destructive',
        });
      }
    }
  }, [router, toast]);

const refreshAuth = useCallback(async () => {
    console.log('Refreshing auth...');  
    try {
      const response = await api.auth.refreshToken();

      if (response.data.success) {
        await loadUser();
        console.log('Auth refreshed successfully');
      } else {
        throw new Error('Token refresh failed');
      }
    } catch (error: any) {
      console.error('Failed to refresh auth:', error);

      const errorMessage = error.response?.data?.message || error.message;

      // Handle specific security scenarios
      if (errorMessage?.includes('already used') || errorMessage?.includes('invalid')) {
        toast({
          title: 'Security Alert',
          description: 'Token reuse detected. Please log in again for security.',
          variant: 'destructive',
        });
      } else {
        toast({
          title: 'Session expired',
          description: 'Please log in again.',
          variant: 'destructive',
        });
      }

      setUser(null);
      router.push('/login');
    }
  }, [loadUser, router, toast]);

  return (
    <AuthContext.Provider value={{ user, login, register, logout, isAuthenticated: !!user, isLoading, refreshAuth }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

'use client';

import { createContext, useContext, ReactNode, useMemo } from 'react';
import { useSocket } from '@/hooks/use-socket';

type SocketHookType = ReturnType<typeof useSocket>;

interface SocketContextType {
  actions: {
    connectSocket: SocketHookType['connectSocket'];
    clearMessages: SocketHookType['clearMessages'];
    joinRoom: SocketHookType['joinRoom'];
    leaveRoom: SocketHookType['leaveRoom'];
    sendMessage: SocketHookType['sendMessage'];
    startTyping: SocketHookType['startTyping'];
    stopTyping: SocketHookType['stopTyping'];
  };
  data: {
    isConnected: SocketHookType['isConnected'];
    connectionState: SocketHookType['connectionState'];
    lastError: SocketHookType['lastError'];
    reconnectAttempts: SocketHookType['reconnectAttempts'];
    joinedRooms: SocketHookType['joinedRooms'];
    joiningRooms: SocketHookType['joiningRooms'];
    realtimeMessages: SocketHookType['realtimeMessages'];
    typingUsers: SocketHookType['typingUsers'];
  };
}

const SocketContext = createContext<SocketContextType | undefined>(undefined);

export function SocketProvider({ children }: { children: ReactNode }) {
  const {
    isConnected,
    connectionState,
    lastError,
    reconnectAttempts,
    joinedRooms,
    joiningRooms,
    realtimeMessages,
    typingUsers,
    connectSocket,
    clearMessages,
    joinRoom,
    leaveRoom,
    sendMessage,
    startTyping,
    stopTyping,
  } = useSocket();

  const actions = useMemo(() => ({
    connectSocket,
    clearMessages,
    joinRoom,
    leaveRoom,
    sendMessage,
    startTyping,
    stopTyping,
  }), [connectSocket, clearMessages, joinRoom, leaveRoom, sendMessage, startTyping, stopTyping]);

  const data = useMemo(() => ({
    isConnected,
    connectionState,
    lastError,
    reconnectAttempts,
    joinedRooms,
    joiningRooms,
    realtimeMessages,
    typingUsers,
  }), [isConnected, connectionState, lastError, reconnectAttempts, joinedRooms, joiningRooms, realtimeMessages, typingUsers]);

  const contextValue = useMemo(() => ({ actions, data }), [actions, data]);

  return (
    <SocketContext.Provider value={contextValue}>
      {children}
    </SocketContext.Provider>
  );
}

export function useSocketContext() {
  const context = useContext(SocketContext);
  if (context === undefined) {
    throw new Error('useSocketContext must be used within a SocketProvider');
  }
  return context;
}

"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import * as React from "react";
import { io, Socket } from "socket.io-client";
import { Message } from "@/lib/types";
import { useAuth } from "@/context/auth-context";
import { useToast } from "@/hooks/use-toast";
import { ToastAction } from "@/components/ui/toast";
import api from "@/lib/api";

const SOCKET_URL = process.env.NODE_ENV === "production" 
  ? "wss://your-domain.com" 
  : "http://localhost:3002";

interface SendMessageData {
  roomId: string;
  content: string;
  messageType?: string;
}

type ConnectionState = 'disconnected' | 'connecting' | 'connected';

export const useSocket = () => {
  const { isAuthenticated, user } = useAuth();
  const { toast } = useToast();

  // Refs for stable references
  const socketRef = useRef<Socket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const isUnmountingRef = useRef(false);

  // State
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [realtimeMessages, setRealtimeMessages] = useState<Message[]>([]);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [reconnectAttempts, setReconnectAttempts] = useState(0);
  const [lastError, setLastError] = useState<string | null>(null);
  const [joinedRooms, setJoinedRooms] = useState<Set<string>>(new Set());
  const [isShutdown, setIsShutdown] = useState(false);

  const maxReconnectAttempts = 5;

  // FIXED: Aligned message handlers with proper type handling
  const handleNewMessage = useCallback((newMessage: Message) => {    
    setRealtimeMessages(prev => {
      // Check for duplicates by server ID
      if (newMessage.id && prev.some(msg => msg.id === newMessage.id)) {
        console.log("🔄 Message already exists, skipping:", newMessage.id);
        return prev;
      }

      // Handle optimistic updates - replace by tempId
      if (newMessage.tempId) {
        const tempIndex = prev.findIndex(msg => 
          msg.tempId === newMessage.tempId
        );

        if (tempIndex > -1) {
          console.log("✅ Replacing optimistic message:", newMessage.tempId);
          const updated = [...prev];
          // FIXED: Properly merge message data and remove tempId
          updated[tempIndex] = { 
            ...newMessage, 
            status: 'sent',
            tempId: undefined // Clear tempId after confirmation
          };
          return updated;
        }
      }

      // New message from another user
      console.log("➕ Adding new message:", newMessage.id);
      return [...prev, { ...newMessage, status: 'sent' }];
    });
  }, []);

  const handleMessageConfirmed = useCallback((confirmedMessage: Message) => {    
    setRealtimeMessages(prev => {
      const index = prev.findIndex(msg =>
        msg.id === confirmedMessage.id ||
        msg.tempId === confirmedMessage.tempId ||
        msg.tempId === confirmedMessage.id
      );

      if (index > -1) {
        const updated = [...prev];
        updated[index] = { 
          ...updated[index],
          ...confirmedMessage, 
          status: 'confirmed',
          tempId: undefined
        };
        return updated;
      }

      return prev;
    });
  }, []);

  const handleMessageError = useCallback((errorData: any) => {
    console.error("❌ Message error:", errorData);

    setRealtimeMessages(prev => 
      prev.map(msg => {
        // Mark failed messages
        if ((errorData.tempId && msg.tempId === errorData.tempId) ||
            (errorData.originalMessageId && msg.id === errorData.originalMessageId)) {
          console.log("❌ Marking message as failed:", msg.tempId || msg.id);
          return { ...msg, status: 'failed' as const };
        }
        return msg;
      })
    );

    toast({
      title: "Message failed",
      description: errorData.message || "Failed to send message",
      variant: "destructive",
    });
  }, [toast]);

  // Socket event handlers
  const setupSocketListeners = useCallback((socket: Socket) => {
    socket.on("connect", () => {
      console.log("✅ Connected to Socket.io server");
      setConnectionState('connected');
      setReconnectAttempts(0);
    });

    socket.on("connected", (data) => {
      console.log("🎯 Socket.io authentication successful:", data);
      // Connection status now shown in header instead of toast
    });

    socket.on("disconnect", (reason) => {
      console.log("❌ Disconnected from Socket.io server:", reason);
      setConnectionState('disconnected');
      setJoinedRooms(new Set());

      if (reason !== "io client disconnect" && !isUnmountingRef.current) {
        setReconnectAttempts(prev => {
          const newAttempts = prev + 1;
          handleReconnection(newAttempts);
          return newAttempts;
        });
      }
    });

    socket.on("error", (data) => {
      console.error("💥 Socket.io error:", data);
      setLastError(data.message || 'Socket error occurred');
      setConnectionState('disconnected');
      // Don't trigger reconnection here - disconnect event will handle it
    });

    socket.on("new_message", handleNewMessage);
    socket.on("message_confirmed", handleMessageConfirmed);
    socket.on("message_error", handleMessageError);

    socket.on("joined_room", (data) => {
      console.log("✅ Successfully joined room:", data.roomId);
      setJoinedRooms(prev => new Set(prev).add(data.roomId));
    });

    socket.on("left_room", (data) => {
      console.log("👋 Successfully left room:", data.roomId);
      setJoinedRooms(prev => {
        const updated = new Set(prev);
        updated.delete(data.roomId);
        return updated;
      });
    });

    socket.on("user_joined", (data) => {
      console.log("👋 User joined:", data.username);
      // Removed toast notification for cleaner UX
    });

    socket.on("user_left", (data) => {
      console.log("👋 User left:", data.username);
      // Removed toast notification for cleaner UX
    });

    socket.on("user_typing", (data) => {
      if (data.userId !== user?.id) {
        setTypingUsers(prev => {
          const newSet = new Set(prev);
          data.isTyping 
            ? newSet.add(data.username) 
            : newSet.delete(data.username);
          return newSet;
        });
      }
    });
  }, [user?.id, toast, handleNewMessage, handleMessageConfirmed, handleMessageError]);

  // Cleanup
  const cleanup = useCallback(() => {
    console.log("🧹 Cleaning up socket connection...");

    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (socketRef.current) {
      socketRef.current.removeAllListeners();
      socketRef.current.disconnect();
      socketRef.current = null;
    }

    setConnectionState('disconnected');
    setJoinedRooms(new Set());
    setReconnectAttempts(0);
  }, []);

  // Connection management
  const connectSocket = useCallback(async () => {
    if (socketRef.current?.connected || !isAuthenticated || isUnmountingRef.current || connectionState === 'connecting' || isShutdown) {
      console.log("🔌 Skipping connection - already connected/connecting, not authenticated, or shutdown");
      return;
    }

    console.log("🔌 Attempting to connect to Socket.io server...");
    setConnectionState('connecting');

    try {
      const wsTokenResponse = await api.auth.getWsToken();
      if (!wsTokenResponse.data.success || !wsTokenResponse.data.token) {
        throw new Error(`Failed to get WebSocket token: ${wsTokenResponse.data.message}`);
      }

      // Clean up existing connection
      if (socketRef.current) {
        socketRef.current.removeAllListeners();
        socketRef.current.disconnect();
      }

      const socket = io(SOCKET_URL, {
        transports: ["websocket"],
        timeout: 10000,
        forceNew: true,
        reconnection: false,
        auth: { token: wsTokenResponse.data.token },
      });

      socketRef.current = socket;
      setupSocketListeners(socket);

      // Connection timeout
      const connectionTimeout = setTimeout(() => {
        if (socket && !socket.connected) {
          console.log("⏰ Connection timeout");
          socket.disconnect();
          setConnectionState('disconnected');
          if (!isUnmountingRef.current) {
            handleReconnection();
          }
        }
      }, 15000);

      socket.on('connect', () => clearTimeout(connectionTimeout));

    } catch (error) {
      console.error("💥 Failed to connect to socket:", error);
      setConnectionState('disconnected');
      setLastError(error instanceof Error ? error.message : 'Connection failed');

      // Connection status now shown in header instead of toast
      if (!isUnmountingRef.current) {
        handleReconnection();
      }
    }
  }, [isAuthenticated, setupSocketListeners, toast, isShutdown]);

  // Reconnection logic
  const handleReconnection = useCallback((currentAttempt?: number) => {
    const attempts = currentAttempt ?? reconnectAttempts;

    // Clear any existing timeout
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (attempts >= maxReconnectAttempts || isUnmountingRef.current || connectionState === 'connecting' || isShutdown) {
      if (attempts >= maxReconnectAttempts && !isShutdown) {
        console.log("❌ Max reconnection attempts reached, shutting down");
        setIsShutdown(true);
        cleanup();

        const retryAction = () => {
          setIsShutdown(false);
          setReconnectAttempts(0);
          connectSocket();
        };

        toast({
          title: "Connection Failed",
          description: "Unable to connect to chat server. Click to retry.",
          variant: "destructive",
          action: React.createElement(ToastAction, {
            altText: "Retry Connection",
            onClick: retryAction
          }, "Retry")
        });
      }
      return;
    }

    const delay = Math.min(1000 * Math.pow(2, attempts), 30000);
    console.log(`🔄 Reconnecting in ${delay}ms (attempt ${attempts + 1})`);

    reconnectTimeoutRef.current = setTimeout(() => {
      if (isAuthenticated && !isUnmountingRef.current && connectionState !== 'connecting' && !isShutdown) {
        connectSocket();
      }
    }, delay);
  }, [reconnectAttempts, isAuthenticated, connectionState, connectSocket, toast, isShutdown, cleanup]);

  // FIXED: Aligned sendMessage with proper typing
  const sendMessage = useCallback((data: SendMessageData) => {
    if (!socketRef.current?.connected) {
      toast({ 
        title: "Not connected", 
        description: "Please wait for connection to be established", 
        variant: "destructive" 
      });
      return;
    }

    if (!data.content.trim()) {
      return;
    }

    const tempId = `temp-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    // FIXED: Create properly typed optimistic message
    const optimisticMessage: Message = {
      id: tempId, // Use tempId as temporary ID
      tempId, // Keep tempId for tracking
      content: data.content.trim(),
      createdAt: new Date().toISOString(),
      userId: user?.id || '',
      username: user?.username || 'You',
      roomId: data.roomId,
      messageType: data.messageType || 'text',
      status: 'sending', // Aligned with type definition
    };

    console.log("🚀 Sending optimistic message:", tempId);

    // Add optimistic message
    setRealtimeMessages(prev => [...prev, optimisticMessage]);

    // Send to server
    socketRef.current.emit('send_message', { 
      ...data, 
      content: data.content.trim(),
      tempId 
    });

    // Auto-fail after timeout if no response
    setTimeout(() => {
      setRealtimeMessages(prev => 
        prev.map(msg => 
          msg.tempId === tempId && msg.status === 'sending'
            ? { ...msg, status: 'failed' }
            : msg
        )
      );
    }, 30000); // 30 second timeout

  }, [user, toast]);

  const joinRoom = useCallback((roomId: string) => {
    if (!socketRef.current?.connected) {
      console.log("📝 Cannot join room, not connected:", roomId);
      return;
    }

    if (joinedRooms.has(roomId)) {
      console.log("🏠 Room already join     ed:", roomId);
      return;
    }

    socketRef.current.emit("join_room", { roomId });
    // console.log(`🏠 Joining room: ${roomId}`);
  }, [joinedRooms]);

  const leaveRoom = useCallback((roomId: string) => {
    if (!socketRef.current?.connected) return;

    socketRef.current.emit("leave_room", { roomId });
    // console.log(`🚪 Leaving room: ${roomId}`);
  }, []);

  const startTyping = useCallback((roomId: string) => {
    if (socketRef.current?.connected) {
      socketRef.current.emit("typing_start", { roomId });
    }
  }, []);

  const stopTyping = useCallback((roomId: string) => {
    if (socketRef.current?.connected) {
      socketRef.current.emit("typing_stop", { roomId });
    }
  }, []);

  const clearMessages = useCallback(() => {
    console.log("🧹 Clearing realtime messages");
    setRealtimeMessages([]);
  }, []);

  // Connection management effects
  useEffect(() => {
    if (isAuthenticated && connectionState === 'disconnected' && !socketRef.current?.connected && !isShutdown) {
      console.log("🔌 Auth state changed, connecting socket...");
      connectSocket();
    } else if (!isAuthenticated && socketRef.current) {
      console.log("🔌 Auth lost, cleaning up socket...");
      cleanup();
    }
  }, [isAuthenticated, connectSocket, cleanup, isShutdown]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      console.log("🔌 Socket hook unmounting...");
      isUnmountingRef.current = true;
      cleanup();
    };
  }, [cleanup]);

  // Error timeout
  useEffect(() => {
    if (lastError) {
      const timer = setTimeout(() => setLastError(null), 10000);
      return () => clearTimeout(timer);
    }
  }, [lastError]);

  return {
    isConnected: connectionState === 'connected',
    connectionState,
    lastError,
    reconnectAttempts,
    joinedRooms: Array.from(joinedRooms),
    realtimeMessages,
    typingUsers,
    connectSocket,
    sendMessage,
    joinRoom,
    leaveRoom,
    startTyping,
    stopTyping,
    clearMessages,
  };
};

